SELECT up.id, up.user_id, up.content, up.artifact_id, up.image_urls AS imageUrls,
       up.like_count AS likeCount, up.comment_count AS commentCount, up.status, up.audit_by AS auditBy, up.audit_time AS auditTime,
       up.reject_reason AS rejectReason, up.created_at,
       u.username, u.avatar_url AS userAvatar,
       a.title_zh AS artifactName
FROM user_posts up
LEFT JOIN users u ON up.user_id = u.id
LEFT JOIN artifacts a ON up.artifact_id = a.id


